"use client";

import { useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { getRandomComplete } from "@/lib/learningMessages";
import { playClick, playCelebrate } from "@/lib/sounds";

// ===== 水果选项 =====
const FRUITS = [
  { emoji: "🍎", name: "苹果", color: "var(--accent)" },
  { emoji: "🍌", name: "香蕉", color: "var(--accent3)" },
  { emoji: "🍇", name: "葡萄", color: "var(--primary)" },
  { emoji: "🍊", name: "橘子", color: "var(--accent2)" },
];

// ===== 12 位同学头像 =====
const STUDENTS = [
  "👦", "👧", "👦", "👧", "👦", "👧",
  "👦", "👧", "👦", "👧", "👦", "👧",
];

export default function TouchPage() {
  const topicId = "data";
  const nextStep = getNextStep(topicId, "touch");

  // 每个同学选择的水果（null = 未选）
  const [choices, setChoices] = useState<(string | null)[]>(
    Array(12).fill(null)
  );
  // 当前选中的同学索引
  const [activeStudent, setActiveStudent] = useState<number | null>(null);
  const [completeMsg, setCompleteMsg] = useState("");

  const allDone = choices.every((c) => c !== null);
  const answeredCount = choices.filter((c) => c !== null).length;

  // 统计每种水果的票数
  const counts = FRUITS.map(
    (f) => choices.filter((c) => c === f.emoji).length
  );

  const handleStudentClick = (idx: number) => {
    if (allDone) return;
    setActiveStudent(idx);
  };

  const handleFruitChoice = (fruitEmoji: string) => {
    if (activeStudent === null) return;
    const next = [...choices];
    next[activeStudent] = fruitEmoji;
    setChoices(next);
    setActiveStudent(null);
    playClick();
    // 全部选完后自动统计
    if (next.every((c) => c !== null)) {
      setCompleteMsg(getRandomComplete());
      setTimeout(() => playCelebrate(), 300);
    }
  };

  return (
    <StepShell topicId={topicId} stepId="touch">
      <div className="space-y-6">
        {/* 说明卡片 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <h2 className="text-lg font-bold text-[var(--text)]">
            调查班级同学最喜欢的水果
          </h2>
          <p className="mt-1 text-sm text-[var(--text-secondary)]">
            点击每个同学，为他选择最喜欢的水果。12 位同学都选完后，看看汇总结果！
          </p>
        </div>

        {/* 水果选项说明 */}
        <div className="flex flex-wrap justify-center gap-3">
          {FRUITS.map((f) => (
            <div
              key={f.emoji}
              className="flex items-center gap-2 rounded-full bg-[var(--bg-card)] px-4 py-2 shadow-[var(--shadow-sm)]"
            >
              <span className="text-2xl">{f.emoji}</span>
              <span className="text-sm font-medium text-[var(--text)]">
                {f.name}
              </span>
            </div>
          ))}
        </div>

        {/* 同学头像区 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          <div className="mb-4 text-center">
            <span className="text-sm text-[var(--text-secondary)]">
              已调查{" "}
              <span className="font-bold text-[var(--primary)]">
                {answeredCount}
              </span>{" "}
              / 12 位同学
            </span>
          </div>

          {/* 进度条 */}
          <div className="mb-5 h-3 w-full overflow-hidden rounded-full bg-[var(--bg-soft)]">
            <div
              className="h-full rounded-full bg-[var(--primary)] transition-all duration-500"
              style={{ width: `${(answeredCount / 12) * 100}%` }}
            />
          </div>

          <div className="grid grid-cols-4 gap-3 sm:grid-cols-6">
            {STUDENTS.map((emoji, idx) => {
              const choice = choices[idx];
              const isActive = activeStudent === idx;
              return (
                <button
                  key={idx}
                  onClick={() => handleStudentClick(idx)}
                  disabled={allDone}
                  className={`flex flex-col items-center gap-1 rounded-[var(--radius-sm)] border-2 p-3 transition-all disabled:cursor-default ${
                    isActive
                      ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10 ring-4 ring-[var(--signal-focus)]/20"
                      : choice
                      ? "border-[var(--signal-confirmed)] bg-[var(--bg-soft)]"
                      : "border-[var(--border)] bg-[var(--bg-card)] hover:-translate-y-0.5 hover:border-[var(--primary-light)]"
                  }`}
                >
                  <span className="text-3xl">{emoji}</span>
                  <span className="text-xs text-[var(--text-muted)]">
                    同学{idx + 1}
                  </span>
                  {choice ? (
                    <span className="text-2xl">{choice}</span>
                  ) : (
                    <span className="text-xs text-[var(--text-muted)]">?</span>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* 水果选择面板 */}
        {activeStudent !== null && !allDone && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]">
            <p className="mb-4 text-center font-medium text-[var(--text)]">
              为同学{activeStudent + 1} {STUDENTS[activeStudent]} 选择最喜欢的水果：
            </p>
            <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
              {FRUITS.map((f) => (
                <button
                  key={f.emoji}
                  onClick={() => handleFruitChoice(f.emoji)}
                  className="flex flex-col items-center gap-2 rounded-[var(--radius-sm)] border-2 border-[var(--border)] bg-[var(--bg-soft)] py-4 transition-all hover:-translate-y-1 hover:border-[var(--signal-focus)] hover:bg-[var(--signal-focus)]/10 active:scale-95"
                >
                  <span className="text-4xl">{f.emoji}</span>
                  <span className="text-sm font-medium text-[var(--text)]">
                    {f.name}
                  </span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* 未完成时的提示 */}
        {!allDone && activeStudent === null && answeredCount > 0 && (
          <p className="text-center text-sm text-[var(--text-secondary)]">
            继续点击还没选择的同学吧！
          </p>
        )}
        {!allDone && activeStudent === null && answeredCount === 0 && (
          <p className="text-center text-sm text-[var(--text-secondary)]">
            点击任意一位同学开始调查吧！
          </p>
        )}

        {/* 汇总结果 */}
        {allDone && (
          <div className="animate-float-in space-y-4">
            {/* 统计卡片 */}
            <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]">
              <h3 className="mb-4 text-center text-lg font-bold text-[var(--text)]">
                调查结果汇总
              </h3>
              <div className="grid grid-cols-2 gap-4 sm:grid-cols-4">
                {FRUITS.map((f, i) => (
                  <div
                    key={f.emoji}
                    className="flex flex-col items-center gap-2 rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-4"
                  >
                    <span className="text-4xl">{f.emoji}</span>
                    <span className="text-sm text-[var(--text-secondary)]">
                      {f.name}
                    </span>
                    <span className="text-3xl font-bold text-[var(--text)]">
                      {counts[i]}
                      <span className="text-sm font-normal text-[var(--text-muted)]">
                        {" "}
                        人
                      </span>
                    </span>
                  </div>
                ))}
              </div>
              <p className="mt-4 text-center text-sm text-[var(--text-secondary)]">
                苹果{counts[0]}人、香蕉{counts[1]}人、葡萄{counts[2]}人、
                橘子{counts[3]}人
              </p>
            </div>

            {/* 完成卡片 */}
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <div className="animate-bounce-soft text-5xl">🎉</div>
              <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
                {completeMsg}
              </h2>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                你已经完成了数据收集！这就是&ldquo;调查&rdquo;的过程——一个一个地问，
                把结果记下来。
              </p>
              {nextStep ? (
                <Link
                  href={nextStep.path}
                  className="mt-6 inline-block rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              ) : (
                <Link
                  href={`/learn/${topicId}`}
                  className="mt-6 inline-block rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
                >
                  ← 回到学习路径
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
